import React from "react"
import styled from "styled-components"
import { Link } from "gatsby"
import "./layout.scss"

const Main = styled.main`
  width: 100%;
  margin: 60px auto 0;
`
const Footer = styled.div`
  width: 100%;
  max-width: 840px;
  margin: 0 auto;
  padding: 50px 20px 70px;
`
const FooterInner = styled.div`
  display: flex;
  justify-content: space-between;
`

class Layout extends React.Component {
  componentDidMount() {
    console.log(
      "%c chichi <3 Developers ",
      "font-size: 34px; padding: 16px;font-weight:bold; color:#ffffff;background-color: #3A91EE"
    )
  }
  render() {
    const { title, children } = this.props
    const header = (
      <h1 className="logo">
        <Link
          style={{
            boxShadow: `none`,
            textDecoration: `none`,
            color: `inherit`,
          }}
          to={`/`}
        >
          {title}
        </Link>
      </h1>
    )
    const navigation = (
      <div className="gnb">
        <Link to={`/apps`}>Apps</Link>
        <Link to={`/category/치치`}>치치</Link>
        <Link to={`/category/리뷰`}>리뷰</Link>
        <Link to={`/category/개발`}>개발</Link>
      </div>
    )
    return (
      <div id="wrap">
        <header id="header">
          <div className="layout-inner">
            {header}
            {navigation}
          </div>
        </header>
        <Main>{children}</Main>
        <Footer>
          <FooterInner>
            <span>© chichi.space</span>
            <div className="social">
              <a
                href="https://github.com/jyqry"
                className="icon github"
                target="_blank"
              ></a>
              <a
                href="https://www.facebook.com/chichidotspace/"
                className="icon facebook"
                target="_blank"
              ></a>
            </div>
          </FooterInner>
        </Footer>
      </div>
    )
  }
}

export default Layout
